import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge case: empty
  it.todo("empty item list yields premium 5 G (processing fee only)");

  // Base premiums for main items (no modifiers, with fee)
  it.todo("single sword for newcomer first contract: 100 base + 10 first + 5 fee = 115 G");
  it.todo("single amulet for newcomer first contract: 60 base + 6 first + 5 fee = 71 G");
  it.todo("single staff for newcomer first contract: 80 base + 8 first + 5 fee = 93 G");
  it.todo("single potion for newcomer first contract: 40 base + 4 first + 5 fee = 49 G");

  // Components
  it.todo("2 runes: 50 G base premium (+10% first +fee) = 60 G");
  it.todo("3 runes: 60 G base premium (block applies) (+10% first +fee) = 71 G");
  it.todo("4 runes: 100 G base premium (no block - block requires exactly 3) (+10% +fee) = 115 G");
  it.todo("7 runes: 175 G base premium (+10% +fee) = 198 G (rounded up from 197.5)");

  // Alike component clarification
  it.todo("2 runes + 1 moonstone: 75 G base (no block: different types)");
  it.todo("3 runes + 3 moonstones: 120 G base (two separate blocks)");

  // Premium modifiers
  it.todo("newcomer cursed sword (steel, enchantment 3): 165 G (100 base + 50 curse + 10 first + 5 fee)");
  it.todo("sword with exactly enchantment 5: high-enchantment surcharge applies");
  it.todo("sword with enchantment 4: no high-enchantment surcharge");
  it.todo("sword cursed and enchantment 5: both surcharges apply");
  it.todo("customer with exactly 2 years: loyalty discount applies");

  // Modifier scope on multi-item policies
  it.todo("policy with cursed sword and plain amulet: cursed surcharge only on cursed item");

  // Integration: long-standing customer's second contract
  it.todo("3yr customer 2nd contract, cursed sword enchantment 7: 160 G");

  // Rounding
  it.todo("premium calculation yielding 197.5 G rounds UP to 198 G");

  // Claim - simple
  it.todo("standard sword (steel, enchantment 3) damage 500 G: payout 400 G");
  it.todo("rune damage 200 G: payout 100 G (no special clauses)");

  // Claim with high enchantment
  it.todo("dragon-material sword enchantment 8 damage 1000 G: payout 400 G (high-enchant then deductible)");
  it.todo("dragon-material sword enchantment 9 damage 1000 G: payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 5 damage 800 G: payout 700 G (dragon full, then deductible)");
  it.todo("steel sword enchantment 9 damage 1000 G: payout 400 G (50% then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G");

  // Multiple items of same type
  it.todo("two swords: insurance sum 2000 G, cap 4000 G");
  it.todo("two swords both damaged: each entry treated as separate damage with own deductible");
  it.todo("damages array has more entries of a type than policy covers: CLI exits non-zero");

  // Cap
  it.todo("policy: sword + amulet: insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword cap based on unmodified insurance value: cap 2000 G");
  it.todo("policy sword + 3 runes block: insurance sum 1750 G");
  it.todo("two successive claims of 1500 G on sword (cap 2000): first 1400, second 600, remainingCap 0");

  // Rounding payout
  it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 G");

  // Errors
  it.todo("unknown item type in quote (e.g. broomstick): CLI exits non-zero");
  it.todo("claim references damage of item not in policy: CLI exits non-zero");
  it.todo("claim damage amount negative: CLI exits non-zero");
});

