type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

type QuoteStep = { op: "quote"; items: Item[] };

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<Record<string, unknown>>;
};

export type ScenarioResult = {
  results: Array<Record<string, unknown>>;
};

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const baseTotalForGroup = (group: Item[]): number => {
  const type = group[0].type;
  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
    return BLOCK_PREMIUM;
  }
  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
};

const baseTotalFor = (items: Item[]): number => {
  let total = 0;
  for (const group of groupByType(items).values()) {
    total += baseTotalForGroup(group);
  }
  return total;
};

const CURSED_SURCHARGE_RATE = 0.5;

const itemSurchargesFor = (items: Item[]): number => {
  return items.reduce((sum, item) => {
    let s = 0;
    if (item.cursed) s += basePremiumFor(item) * CURSED_SURCHARGE_RATE;
    return sum + s;
  }, 0);
};

const quotePremium = (items: Item[]): number => {
  const baseTotal = baseTotalFor(items);
  const itemSurcharges = itemSurchargesFor(items);
  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(baseTotal + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    const quote = step as unknown as QuoteStep;
    return { premium: quotePremium(quote.items) };
  });
  return { results };
};

