import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge case: empty
  it("empty item list yields premium 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums for main items (no modifiers, with fee)
  it("single sword for newcomer first contract: 100 base + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet for newcomer first contract: 60 base + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff for newcomer first contract: 80 base + 8 first + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion for newcomer first contract: 40 base + 4 first + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Components
  it("2 runes: 50 G base premium (+10% first +fee) = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes: 60 G base premium (block applies) (+10% first +fee) = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes: 100 G base premium (no block - block requires exactly 3) (+10% +fee) = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array(4).fill({ type: "rune" }) }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes: 175 G base premium (+10% +fee) = 198 G (rounded up from 197.5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // Alike component clarification
  it("2 runes + 1 moonstone: 75 G base (no block: different types) = 88 G premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones: 120 G base (two separate blocks) = 137 G premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Premium modifiers
  it("newcomer cursed sword (steel, enchantment 3): 165 G (100 base + 50 curse + 10 first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword with exactly enchantment 5: high-enchantment surcharge applies = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4: no high-enchantment surcharge = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("sword cursed and enchantment 5: both surcharges apply = 195 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 195 }] });
  });
  it("customer with exactly 2 years: loyalty discount applies = 95 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });

  // Modifier scope on multi-item policies
  it("policy with cursed sword and plain amulet: cursed surcharge only on cursed item = 231 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "sword", material: "steel", enchantment: 3, cursed: true },
          { type: "amulet", material: "silver", enchantment: 2, cursed: false },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // Integration: long-standing customer's second contract
  it("3yr customer 2nd contract, cursed sword enchantment 7: 160 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
        },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 7, cursed: true }],
        },
      ],
    });
    expect(result.results[1]).toEqual({ premium: 160 });
  });

  // Rounding
  it.todo("premium calculation yielding 197.5 G rounds UP to 198 G");

  // Claim - simple
  it.todo("standard sword (steel, enchantment 3) damage 500 G: payout 400 G");
  it.todo("rune damage 200 G: payout 100 G (no special clauses)");

  // Claim with high enchantment
  it.todo("dragon-material sword enchantment 8 damage 1000 G: payout 400 G (high-enchant then deductible)");
  it.todo("dragon-material sword enchantment 9 damage 1000 G: payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 5 damage 800 G: payout 700 G (dragon full, then deductible)");
  it.todo("steel sword enchantment 9 damage 1000 G: payout 400 G (50% then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G");

  // Multiple items of same type
  it.todo("two swords: insurance sum 2000 G, cap 4000 G");
  it.todo("two swords both damaged: each entry treated as separate damage with own deductible");
  it.todo("damages array has more entries of a type than policy covers: CLI exits non-zero");

  // Cap
  it.todo("policy: sword + amulet: insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword cap based on unmodified insurance value: cap 2000 G");
  it.todo("policy sword + 3 runes block: insurance sum 1750 G");
  it.todo("two successive claims of 1500 G on sword (cap 2000): first 1400, second 600, remainingCap 0");

  // Rounding payout
  it.todo("payout calculation yielding 350.5 G rounds DOWN to 350 G");

  // Errors
  it.todo("unknown item type in quote (e.g. broomstick): CLI exits non-zero");
  it.todo("claim references damage of item not in policy: CLI exits non-zero");
  it.todo("claim damage amount negative: CLI exits non-zero");
});

