const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;

const insuranceSumFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);

const payoutForDamage = (damage: Damage): number => {
  return Math.max(0, damage.amount - DEDUCTIBLE);
};

const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
  const grossPayout = incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
  const payout = Math.min(grossPayout, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
