  const payout = Math.min(grossPayout, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const policies: Record<number, Policy> = {};
  const results = scenario.steps.map((step, index) => {
    if ((step as { op: string }).op === "quote") {
      const quote = step as unknown as QuoteStep;
      const isFollowUp = quoteCount > 0;
      quoteCount += 1;
      const insuranceSum = insuranceSumFor(quote.items);
      policies[index] = {
        items: quote.items,
        insuranceSum,
        remainingCap: insuranceSum * CAP_MULTIPLIER,
      };
      return { premium: quotePremium(quote.items, scenario.customer, isFollowUp) };
    }
    const claim = step as unknown as ClaimStep;
    return processClaim(policies[claim.policy], claim.incident);
  });
  return { results };
};

