    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // Alike component clarification
  it("2 runes + 1 moonstone: 75 G base (no block: different types) = 88 G premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
